const areSceneInnerPropsEqual = (prev, next) => {
    const ignoreHidden = next?.useGpuVisibilityMask === true;
    const ignored = ignoreHidden
        ? new Set(["hiddenDeckIds", "hiddenRoomIds", "hiddenGroupIds", "hiddenRoomGroupIds"])
        : null;
    const prevKeys = Object.keys(prev || {});
    const nextKeys = Object.keys(next || {});
    if (prevKeys.length !== nextKeys.length) return false;
    for (let i = 0; i < nextKeys.length; i++) {
        const key = nextKeys[i];
        if (ignored && ignored.has(key)) continue;
        if (prev[key] !== next[key]) return false;
    }
    return true;
};
const SceneInnerMemo = React.memo(SceneInner, areSceneInnerPropsEqual);

const __publicBasePath = () => {
    const envBase = String(process.env.PUBLIC_URL || "").replace(/\/+$/, "");
    if (envBase) return envBase;
    if (typeof window === "undefined") return "";
    try {
        const url = new URL(".", window.location.href);
        const path = String(url.pathname || "").replace(/\/+$/, "");
        return path === "/" ? "" : path;
    } catch {
        const path = String(window.location?.pathname || "").replace(/\/+$/, "");
        return path === "/" ? "" : path;
    }
};

const __workerUrl = (name) => {
    const base = __publicBasePath();
    return `${base}/workers/${name}`;
};

const __linkAlphaLabel = (index) => {
    let n = Math.max(0, Number(index) || 0);
    if (!n) return "A";
    let label = "";
    while (n > 0) {
        n -= 1;
        label = String.fromCharCode(65 + (n % 26)) + label;
        n = Math.floor(n / 26);
    }
    return label || "A";
};

const __linkKey = (fromId, toId) => `${fromId || ""}::${toId || ""}`;
const __linkSetKey = (fromId, toId, setId) => `${fromId || ""}::${toId || ""}::${setId || ""}`;
const LINK_SET_DEFAULT_ID = "ls-a";
const LINK_SET_DEFAULT_NAME = "Set A";
const __linkSetLabel = (set, fallbackIndex = 0) => {
    const name = String(set?.name ?? set?.label ?? "").trim();
    if (name) return name;
    if (set?.id === LINK_SET_DEFAULT_ID) return LINK_SET_DEFAULT_NAME;
    return `Set ${__linkAlphaLabel(fallbackIndex + 1)}`;
};
const __normalizeLinkSetLabel = (label) => String(label || "").trim().toLowerCase();

function WebGPUWarmup({ frames = 6 }) {
    const { gl, scene, camera } = useThree();
    useEffect(() => {
        if (!gl?.isWebGPURenderer) return undefined;
        let raf = 0;
        let count = 0;
        const tick = () => {
            if (!gl?.isWebGPURenderer) return;
            try {
                if (typeof gl.compile === "function") gl.compile(scene, camera);
                gl.render(scene, camera);
            } catch {}
            count += 1;
            if (count < frames) raf = requestAnimationFrame(tick);
        };
        raf = requestAnimationFrame(tick);
        return () => cancelAnimationFrame(raf);
    }, [gl, scene, camera, frames]);
    return null;
}

function UIRootMount({ children }) {
    const rootRef = useRef(null);
    useEffect(() => {
        if (typeof document === "undefined") return undefined;
        const host = document.getElementById("ui-root");
        if (!host) return undefined;
        rootRef.current = ReactDOM.createRoot(host);
        return () => {
            rootRef.current?.unmount();
            rootRef.current = null;
        };
    }, []);
    useEffect(() => {
        if (rootRef.current) rootRef.current.render(children);
    }, [children]);
    return null;
}
