    const eventTimersRef = useRef(new Map());
    useEffect(() => {
        const timers = eventTimersRef.current;
        (events || []).forEach((ev) => {
            if (!ev || !ev.id) return;
            const enabled = ev.enabled !== false;
            const loop = ev.loop !== false;
            const duration = Math.max(0, Number(ev.duration ?? 0) || 0);
            if (enabled && !loop && duration > 0) {
                if (timers.has(ev.id)) return;
                const t = setTimeout(() => {
                    setEvents((prev) => prev.map((e) => (e.id === ev.id ? { ...e, enabled: false } : e)));
                    timers.delete(ev.id);
                }, duration * 1000);
                timers.set(ev.id, t);
            } else if (timers.has(ev.id)) {
                clearTimeout(timers.get(ev.id));
                timers.delete(ev.id);
            }
        });
        return () => {
            timers.forEach((t) => clearTimeout(t));
            timers.clear();
        };
    }, [events, setEvents]);
    const [linkFromId, setLinkFromId] = useState(null);
