    const dispatchHandClick = useCallback((nx, ny) => {
        if (typeof window === "undefined" || typeof document === "undefined") return;
        const x = Math.round(nx * window.innerWidth);
        const y = Math.round(ny * window.innerHeight);
        const pick = (els) => {
            const clickable = els.find((e) =>
                e &&
                e !== document.body &&
                e !== document.documentElement &&
                e.tagName !== "CANVAS" &&
                (e.tagName === "BUTTON" ||
                    e.tagName === "A" ||
                    e.tagName === "INPUT" ||
                    e.tagName === "SELECT" ||
                    e.tagName === "TEXTAREA" ||
                    e.getAttribute?.("role") === "button" ||
                    e.onclick ||
                    e.onpointerdown)
            );
            return clickable || els.find((e) => e && e.tagName !== "CANVAS");
        };
        const el = pick(document.elementsFromPoint(x, y) || []);
        if (!el) return;
        const evInit = { bubbles: true, cancelable: true, clientX: x, clientY: y };
        el.focus?.();
        if (el.tagName !== "CANVAS") {
            try {
                el.dispatchEvent(new PointerEvent("pointerdown", { ...evInit, pointerId: 1, pointerType: "mouse", isPrimary: true }));
                el.dispatchEvent(new PointerEvent("pointerup", { ...evInit, pointerId: 1, pointerType: "mouse", isPrimary: true }));
            } catch {}
        }
        el.dispatchEvent(new MouseEvent("mousedown", evInit));
        el.dispatchEvent(new MouseEvent("mouseup", evInit));
        el.dispatchEvent(new MouseEvent("click", evInit));
    }, []);

