                    if (!l) continue;
                    if (!rotatingNodeIds.has(l.from) || !rotatingNodeIds.has(l.to)) continue;
                    const bps = Array.isArray(l.breakpoints) ? l.breakpoints : null;
                    if (!bps || !bps.length) continue;
                    ref.linkBpStarts.set(
                        l.id,
                        bps.map((bp) => [bp?.[0] ?? 0, bp?.[1] ?? 0, bp?.[2] ?? 0])
                    );
