    const addRoomConfiguratorNodes = useCallback((roomId, items) => {
        const room = (roomsRef.current || []).find((r) => r.id === roomId);
        if (!room) return;
        const list = Array.isArray(items) ? items : [];
        const shapeQueue = [];
        for (const it of list) {
            const qtyRaw = Number(it?.quantity ?? it?.qty ?? 1);
            const qty = Math.max(1, Math.min(500, Math.floor(Number.isFinite(qtyRaw) ? qtyRaw : 1)));
            const shape = it?.shape || "sphere";
            const name = (it?.name || "").trim();
            const cluster = it?.cluster || null;
            const linkTo = it?.linkTo || "";
            const listId = it?.listId || null;
            const linkToItemId = it?.linkToItemId || "";
            const linkToName = (it?.linkToName || "").trim();
            const linkStyle = it?.linkStyle || "particles";
            const linkCount = it?.linkCount ?? "";
            const linkColor = it?.linkColor || "";
            for (let i = 0; i < qty; i++) {
                shapeQueue.push({
                    shape,
                    name,
                    cluster,
                    linkTo,
                    listId,
                    linkToItemId,
                    linkToName,
                    linkStyle,
                    linkCount,
                    linkColor,
                });
            }
        }
        if (!shapeQueue.length) return;

        const size = room.size || [3, 1.6, 2.2];
        const center = room.center || [0, (Number(size[1]) || 1.6) * 0.5, 0];
        const rotY = Number(room?.rotation?.[1] ?? 0) || 0;
        const cos = Math.cos(rotY);
        const sin = Math.sin(rotY);

        const cols = Math.ceil(Math.sqrt(shapeQueue.length));
        const rows = Math.ceil(shapeQueue.length / cols);
        const usableX = Math.max(0.1, Number(size[0]) * 0.7);
        const usableZ = Math.max(0.1, Number(size[2]) * 0.7);
        const stepX = cols > 1 ? usableX / (cols - 1) : 0;
        const stepZ = rows > 1 ? usableZ / (rows - 1) : 0;
        const startX = center[0] - (cols - 1) * 0.5 * stepX;
        const startZ = center[2] - (rows - 1) * 0.5 * stepZ;
        const floorY = center[1] - (Number(size[1]) || 1.6) * 0.5;
        const baseY = floorY + 0.1;

        const baseIndex = (nodesRef.current || []).length;
        const roomPrefix = room.label || room.name || `Room ${room.id}`;
        const nameCounts = new Map();
        shapeQueue.forEach((entry) => {
            const base = (entry?.name || "").trim();
            if (!base) return;
            nameCounts.set(base, (nameCounts.get(base) || 0) + 1);
        });
        const nameIndex = new Map();
        const getShapeLabel = (shapeObj, fallback = "Node") => {
            const rawType = String(shapeObj?.type || "").toLowerCase();
            if (rawType === "model") {
                const name = shapeObj?.name || shapeObj?.modelName || shapeObj?.label;
                return name ? String(name) : "Model";
            }
            const map = {
                sphere: "Sphere",
                box: "Box",
                square: "Box",
                cylinder: "Cylinder",
                cone: "Cone",
                disc: "Disc",
                circle: "Circle",
                hexagon: "Hexagon",
                switch: "Switch",
                tv: "TV",
                remote: "Remote",
                accesspoint: "Access Point",
                laviebox: "LAVIE Box",
                amplifier: "Amplifier",
                ipad: "iPad",
                speaker: "Speaker Ceiling",
                speakerfloor: "Speaker Ground",
                soundbar: "Soundbar",
                headphones: "Headphones",
                subwoofer: "Subwoofer",
                subwoofer: "Subwoofer",
            };
            return map[rawType] || fallback;
        };
        const newNodes = shapeQueue.map((entry, i) => {
            const col = i % cols;
            const row = Math.floor(i / cols);
            let x = startX + col * stepX;
            let z = startZ + row * stepZ;
            const dx = x - center[0];
            const dz = z - center[2];
            x = center[0] + dx * cos - dz * sin;
            z = center[2] + dx * sin + dz * cos;

            const shape = resolveRoomConfigShape(entry?.shape);
            const isSwitch = shape.type === "switch";
            const labelBase = getShapeLabel(shape, isSwitch ? "Switch" : "Node");
            const fallbackLabel = `${labelBase} ${baseIndex + i + 1}`;
            let nameLabel = "";
            const baseName = (entry?.name || "").trim();
            if (baseName) {
                const total = nameCounts.get(baseName) || 0;
                const nextIdx = (nameIndex.get(baseName) || 0) + 1;
                nameIndex.set(baseName, nextIdx);
                nameLabel = total > 1 ? `${baseName} ${nextIdx}` : baseName;
            }
            const finalLabel = baseName ? `${roomPrefix} ${nameLabel}` : `${roomPrefix} ${fallbackLabel}`;
            const finalCluster = entry?.cluster || (isSwitch ? "Network" : "AV");
            return {
                id: uuid(),
                kind: isSwitch ? "switch" : "node",
                label: finalLabel,
                position: [x, baseY, z],
                rotation: [0, 0, 0],
                role: isSwitch ? "bidir" : "sender",
                cluster: finalCluster,
                color: isSwitch ? "#9bd0ff" : "#6ee7d8",
                glowOn: false,
                glow: 0.3,
                shape,
                light: { type: "none", enabled: false },
                anim: {},
                signal: { style: "off", speed: 1, size: 1 },
                switch: isSwitch ? {
                    buttonsCount: 2,
                    physical: false,
                    physicalHeight: 0.028,
                    margin: 0.03,
                    gap: 0.02,
                    pressDepth: 0.014,
                    pressMs: 140,
                    textColor: "#e2e8f0",
                    textScale: 1,
                    buttonColor: "#22314d",
                    pressedColor: "#101a2d",
                    hoverEmissive: "#ffffff",
                    buttons: [
                        { name: "On", actionIds: [] },
                        { name: "Off", actionIds: [] },
                    ],
                } : undefined,
                roomId: room.id,
            };
        });

        setNodes((prev) => [...prev, ...newNodes]);

        const linkAdditions = [];
        const existingLinks = linksRef.current || [];
        const listIdToNodeId = new Map();
        newNodes.forEach((node, idx) => {
            const listId = shapeQueue[idx]?.listId;
            if (listId && node?.id) listIdToNodeId.set(listId, node.id);
        });
        const newNodeById = new Map();
        newNodes.forEach((node, idx) => {
            newNodeById.set(node.id, { node, entry: shapeQueue[idx] });
        });
        const listNameToNodeId = new Map();
        const listFullNameToNodeId = new Map();
        newNodes.forEach((node, idx) => {
            const baseName = (shapeQueue[idx]?.name || "").trim();
            if (baseName && !listNameToNodeId.has(baseName.toLowerCase())) {
                listNameToNodeId.set(baseName.toLowerCase(), node.id);
            }
            if (node?.label) {
                listFullNameToNodeId.set(String(node.label).trim().toLowerCase(), node.id);
            }
        });
        const existingNameToId = new Map();
        (nodesRef.current || []).forEach((n) => {
            const label = String(n?.label || n?.name || "").trim().toLowerCase();
            if (label && !existingNameToId.has(label)) existingNameToId.set(label, n.id);
        });
        const resolveTargetId = (entry) => {
            const byList = entry?.linkToItemId ? listIdToNodeId.get(entry.linkToItemId) : null;
            if (byList) return byList;
            const rawLink = entry?.linkTo || "";
            if (rawLink) return listIdToNodeId.get(rawLink) || rawLink;
            const name = (entry?.linkToName || "").trim().toLowerCase();
            if (!name) return null;
            return listNameToNodeId.get(name) || listFullNameToNodeId.get(name) || existingNameToId.get(name) || null;
        };
        const getShapeType = (shapeValue, node) => {
            if (typeof shapeValue === "string" && shapeValue) {
                return shapeValue.split(":")[0].toLowerCase();
            }
            const t = node?.shape?.type || "";
            return String(t || "").toLowerCase();
        };
        const getDefaultLinkColor = (fromEntry, toId) => {
            const fromType = getShapeType(fromEntry?.shape, null);
            const toInfo = newNodeById.get(toId);
            const toNode = toInfo?.node || (nodesRef.current || []).find((n) => n?.id === toId);
            const toType = getShapeType(toInfo?.entry?.shape, toNode);
            if (fromType === "speaker" && toType === "amplifier") return "#91c3f3";
            if (fromType === "laviebox") return "#65ec74";
            if (fromType === "accesspoint") return "#dc49df";
            return null;
        };
        for (let i = 0; i < newNodes.length; i++) {
            const entry = shapeQueue[i];
            const toId = resolveTargetId(entry);
            if (!toId) continue;
            const fromId = newNodes[i]?.id;
            if (!fromId || fromId === toId) continue;
            const linkSetId = getActiveLinkSetIdForNode?.(fromId);
            const label = getNextLinkLabel?.(fromId, toId, linkAdditions, linkSetId) || __linkAlphaLabel(1);
            const style = entry?.linkStyle || linkDefaults?.style || "particles";
            const countRaw = Number(entry?.linkCount);
            const count = Number.isFinite(countRaw) ? Math.max(1, Math.round(countRaw)) : null;
            const color = entry?.linkColor || getDefaultLinkColor(entry, toId) || linkDefaults?.color;
            const linkPatch = {
                style,
                ...(color ? { color } : {}),
            };
            if (count != null) {
                if (style === "cable") {
                    linkPatch.cable = { ...(linkDefaults?.cable || {}), count };
                } else if (style === "particles") {
                    linkPatch.particles = { ...(linkDefaults?.particles || {}), count };
                }
            }
            linkAdditions.push({
                id: uuid(),
                from: fromId,
                to: toId,
                label,
                description: "",
                linkSetId,
                ...(linkDefaults || {}),
                ...linkPatch,
            });
        }
        if (linkAdditions.length) {
            setLinks((prev) => [...prev, ...linkAdditions]);
        }
    }, [getActiveLinkSetIdForNode, getNextLinkLabel, linkDefaults, setLinks, resolveRoomConfigShape, setNodes]);
// keep panel scroll position across action edits
    const leftColRef = useRef(null);
    const keepLeftScroll = React.useCallback((fn) => {
        const el = leftColRef.current;
        const y = el ? el.scrollTop : 0;
        fn();
        requestAnimationFrame(() => { if (el) el.scrollTop = y; });
    }, []);
// Stops only <a href="#"> clicks</a> from scrolling to top
