    function runAction(action) {
        if (!action || !Array.isArray(action.steps)) return;

        // Camera timeline cursor in seconds (camera moves still chain)
        let cameraCursor = 0;

        const scheduleWireStep = (step, startSec) => {
            const targetOn = (step.value || "on") === "on";

            const runWire = () => {
                setWireframe((cur) => {
                    const curBool = !!cur;
                    // no-op if already in desired state
                    if (curBool === targetOn) return cur;
                    return targetOn;
                });
            };

            if (startSec <= 0) runWire();
            else setTimeout(runWire, startSec * 1000);
        };
        const scheduleSceneLightsStep = (step, startSec) => {
            const mode = String(step.value || "on").toLowerCase();
            const runLights = () => {
                setShowLights((cur) => {
                    if (mode === "toggle") return !cur;
                    if (mode === "off") return false;
                    return true;
                });
            };
            if (startSec <= 0) runLights();
            else setTimeout(runLights, startSec * 1000);
        };

        const scheduleWireOpacityStep = (step, startSec) => {
            const target = Math.max(0, Math.min(1, Number(step?.wireOpacityValue ?? step?.opacity ?? 0.6)));
            const duration = Math.max(0.01, Number(step?.wireOpacityDuration ?? step?.duration ?? 0.4) || 0.4);

            const runWireOpacity = () => {
                startWireOpacityFade(target, duration);
            };

            if (startSec <= 0) runWireOpacity();
            else setTimeout(runWireOpacity, startSec * 1000);
        };



        const schedulePacketStep = (step, startSec) => {

            const runPkt = async () => {

                // Packet Tracer-style routing (source - target)
                const pktMode = String(step.packetMode || '').toLowerCase();
                const srcId = step.sourceNodeId || step.sourceId || '';
                const dstId = step.targetNodeId || step.targetId || '';
                const cast = String(step.cast || step.castMode || 'unicast').toLowerCase();
                const wantsTrace = step.type === 'packetSend' && (pktMode === 'trace' || pktMode === 'tracer' || (srcId && dstId));

                if (wantsTrace && srcId && dstId) {
                    const clearOnStart = !!step.clearExisting;
                    const dispatchOnLink = (linkId, tStart, travelSec, packetPreset) => {
                        const run = () => {
                            try {
                                const preset = (packetPreset && typeof packetPreset === 'object') ? packetPreset : null;
                                const presetOverrides = preset ? {
                                    packetPreset: preset,
                                    packetStyle: preset.style,
                                    style: preset.style,
                                    text: preset.text,
                                    color: preset.color,
                                    size: preset.size,
                                    opacity: preset.opacity,
                                } : {};

                                window.dispatchEvent(new CustomEvent('EPIC3D_PACKET_CTRL', {
                                    detail: {
                                        action: 'start',
                                        linkId,
                                        allowNonPacket: true,
                                        overrides: {
                                            count: 1,
                                            interval: 0,
                                            loop: false,
                                            clearOnStart,
                                            travel: travelSec,
                                            delay: 0,
                                            ...presetOverrides,
                                        },
                                    },
                                }));
                            } catch (err) {
                                if (process.env.NODE_ENV !== 'production') console.warn('Packet tracer dispatch failed', err);
                            }
                        };
                        if (tStart <= 0) run();
                        else setTimeout(run, tStart * 1000);
                    };

                    if (packetWorkerRef.current) {
                        try {
                            const nodesLite = (nodes || []).map((n) => ({ id: n.id, position: n.position }));
                            const linksLite = (links || []).map((l) => ({
                                id: l.id,
                                from: l.from,
                                to: l.to,
                                packet: l.packet || null,
                            }));
                            const stepLite = {
                                packetMode: "trace",
                                sourceNodeId: srcId,
                                targetNodeId: dstId,
                                cast,
                                delay: step.delay ?? 0,
                                maxEdges: step.maxEdges,
                                maxHops: step.maxHops,
                                multicastFloodAll: step.multicastFloodAll,
                                packetProfileLinkId: step.packetProfileLinkId,
                                packetLinkId: step.packetLinkId,
                                profileLinkId: step.profileLinkId,
                                linkId: step.linkId,
                            };
                            const result = await requestPacketTrace({
                                nodes: nodesLite,
                                links: linksLite,
                                step: stepLite,
                            });
                            if (result && result.ok && Array.isArray(result.schedule)) {
                                const preset = result.packetPreset;
                                result.schedule.forEach((item) => {
                                    if (!item || !item.linkId) return;
                                    const tStart = Number(item.tStart ?? 0) || 0;
                                    const travel = Number(item.travel ?? 0) || 0;
                                    dispatchOnLink(item.linkId, tStart, travel, preset);
                                });
                                return;
                            }
                        } catch (err) {
                            if (process.env.NODE_ENV !== 'production') console.warn('Packet worker failed', err);
                        }
                    }
                    const nodesById = new Map((nodes || []).map((n) => [n.id, n]));
                    const linksArr = Array.isArray(links) ? links : [];
                    const linksById = new Map(linksArr.map((l) => [l.id, l]));

                    const outAdj = new Map();
                    const inAdj = new Map();
                    for (const l of linksArr) {
                        if (!l || !l.from || !l.to) continue;
                        if (!outAdj.has(l.from)) outAdj.set(l.from, []);
                        outAdj.get(l.from).push({ to: l.to, link: l });
                        if (!inAdj.has(l.to)) inAdj.set(l.to, []);
                        inAdj.get(l.to).push({ from: l.from, link: l });
                    }

                    const clamp = (v, a, b) => Math.max(a, Math.min(b, v));
                    const dist3 = (a, b) => {
                        const aa = a && a.position ? a.position : a;
                        const bb = b && b.position ? b.position : b;
                        const ax = (aa && aa[0]) ?? aa?.x ?? 0;
                        const ay = (aa && aa[1]) ?? aa?.y ?? 0;
                        const az = (aa && aa[2]) ?? aa?.z ?? 0;
                        const bx = (bb && bb[0]) ?? bb?.x ?? 0;
                        const by = (bb && bb[1]) ?? bb?.y ?? 0;
                        const bz = (bb && bb[2]) ?? bb?.z ?? 0;
                        const dx = ax - bx, dy = ay - by, dz = az - bz;
                        return Math.sqrt(dx * dx + dy * dy + dz * dz);
                    };

                    const getTravelSec = (link) => {
                        if (!link) return 1.0;
                        const p = link.packet || {};
                        const t = (p.timing && p.timing.travel != null) ? p.timing.travel : (p.travel != null ? p.travel : null);
                        const tt = Number(t);
                        if (Number.isFinite(tt) && tt > 0) return clamp(tt, 0.05, 8);
                        // fallback: based on node distance (units/sec tuned for nice pacing)
                        const a = nodesById.get(link.from);
                        const b = nodesById.get(link.to);
                        const d = dist3(a?.position, b?.position);
                        const sec = d / 2.4;
                        return clamp(sec, 0.25, 4.0);
                    };

                    const normalizePacketStyle = (styleRaw) => {
                        const s0 = String(styleRaw || '').toLowerCase();
                        let s = s0;
                        if (s === 'square') s = 'cube';
                        if (s === 'shard') s = 'diamond';
                        if (s === 'static') s = 'cube';
                        if (s === 'comet') s = 'orb';
                        return s || null;
                    };

                    const getPacketPresetFromLink = (link) => {
                        if (!link) return null;
                        const p = link.packet || {};
                        const v = p.visual || {};
                        const styleRaw = p.style || p.packetStyle || v.shape || v.packetShape || v.style || null;
                        const style = styleRaw ? normalizePacketStyle(styleRaw) : null;
                        const text = p.text || p.label || v.text || null;
                        const color = p.color || v.color || null;
                        const size = (p.size != null ? p.size : (v.size != null ? v.size : null));
                        const opacity = (p.opacity != null ? p.opacity : null);
                        if (style == null && text == null && color == null && size == null && opacity == null) return null;
                        return { style, text, color, size, opacity };
                    };

                    let packetPreset = null;
                    {
                        const profileId = step.packetProfileLinkId || step.packetLinkId || step.profileLinkId || step.linkId || null;
                        if (profileId && linksById.get(profileId)) {
                            packetPreset = getPacketPresetFromLink(linksById.get(profileId));
                        }
                    }

                    const baseDelay = Math.max(0, Number(step.delay ?? 0) || 0);

                    // Unicast: shortest path by hop count
                    const sendUnicast = () => {
                        const prev = new Map();
                        const q = [srcId];
                        prev.set(srcId, null);
                        while (q.length) {
                            const u = q.shift();
                            if (u === dstId) break;
                            const outs = outAdj.get(u) || [];
                            for (const e of outs) {
                                const v = e.to;
                                if (!v || prev.has(v)) continue;
                                prev.set(v, { p: u, linkId: e.link?.id });
                                q.push(v);
                            }
                        }
                        if (!prev.has(dstId)) return false;
                        const hops = [];
                        let cur = dstId;
                        while (cur && cur !== srcId) {
                            const info = prev.get(cur);
                            if (!info || !info.linkId) break;
                            hops.push({ linkId: info.linkId, from: info.p, to: cur });
                            cur = info.p;
                        }
                        hops.reverse();

                        if (!packetPreset && hops.length > 0) {
                            const firstLink = linksById.get(hops[0].linkId);
                            packetPreset = getPacketPresetFromLink(firstLink);
                        }

                        let t = baseDelay;
                        for (const h of hops) {
                            const link = linksById.get(h.linkId);
                            const travel = getTravelSec(link);
                            dispatchOnLink(h.linkId, t, travel, packetPreset);
                            t += travel;
                        }
                        return hops.length > 0;
                    };

                    // Multicast: flood-forward like Packet Tracer (branch at intermediate nodes).
                    // We keep it safe via maxEdges/maxHops and basic loop-avoidance.
                    const sendMulticast = () => {
                        const dist = new Map();
                        dist.set(dstId, 0);
                        const q = [dstId];
                        while (q.length) {
                            const v = q.shift();
                            const dv = dist.get(v) || 0;
                            const ins = inAdj.get(v) || [];
                            for (const e of ins) {
                                const u = e.from;
                                if (!u || dist.has(u)) continue;
                                dist.set(u, dv + 1);
                                q.push(u);
                            }
                        }
                        if (!dist.has(srcId)) return false;

                        if (!packetPreset) {
                            const outs0 = outAdj.get(srcId) || [];
                            // prefer a link that already has packet settings
                            const preferred = outs0.find((e) => e?.link?.packet) || outs0[0];
                            packetPreset = getPacketPresetFromLink(preferred?.link);
                        }

                        const maxEdges = Math.max(20, Math.min(2400, Number(step.maxEdges ?? 640) || 640));
                        const baseHops = dist.get(srcId) || 0;
                        const maxHops = Math.max(1, Math.min(64, Number(step.maxHops ?? (baseHops + 10)) || (baseHops + 10)));

                        let scheduled = 0;
                        const bestHops = new Map();
                        const qq = [{ node: srcId, t: baseDelay, prev: null, hops: 0 }];
                        bestHops.set(srcId, 0);

                        while (qq.length && scheduled < maxEdges) {
                            const st = qq.shift();
                            const u = st.node;
                            if (u === dstId) continue;
                            if (st.hops >= maxHops) continue;

                            const outs = outAdj.get(u) || [];
                            const du = dist.get(u);
                            const sorted = outs.slice().sort((a, b) => {
                                const da = dist.has(a.to) ? dist.get(a.to) : 1e9;
                                const db = dist.has(b.to) ? dist.get(b.to) : 1e9;
                                // prefer routes that are closer-to-target (but still allow detours)
                                if (da !== db) return da - db;
                                return String(a.to).localeCompare(String(b.to));
                            });

                            for (const e of sorted) {
                                const v = e.to;
                                if (!v) continue;
                                if (st.prev && v === st.prev) continue; // avoid immediate bounce-back

                                // Optional prune: require reachability to target.
                                // Default behavior: still allow detours, but only if destination can reach target OR user explicitly wants full flood.
                                const floodAll = (step.multicastFloodAll ?? true) === true;
                                if (!floodAll && !dist.has(v)) continue;

                                const nextHops = st.hops + 1;
                                const best = bestHops.get(v);
                                if (best != null && best <= nextHops) continue;
                                bestHops.set(v, nextHops);

                                const link = e.link;
                                const travel = getTravelSec(link);
                                dispatchOnLink(link.id, st.t, travel, packetPreset);
                                scheduled++;
                                qq.push({ node: v, t: st.t + travel, prev: u, hops: nextHops });
                                if (scheduled >= maxEdges) break;
                            }
                        }
                        return scheduled > 0;
                    };

                    const ok = (cast === 'multicast') ? sendMulticast() : sendUnicast();
                    if (!ok && process.env.NODE_ENV !== 'production') {
                        console.warn('Packet tracer: no path from', srcId, 'to', dstId);
                    }
                    return;
                }

                const linkId = step.linkId || "__ALL_PACKET__";

                const isAll = linkId === "__ALL_PACKET__" || linkId === "__ALL__" || linkId === "*";

                try {

                    if (step.type === "packetSend") {

                        const overrides = {

                            count: Math.max(1, Math.round(Number(step.count ?? 1) || 1)),

                            interval: Math.max(0, Number(step.interval ?? 0.15) || 0),

                            loop: !!step.loop,

                            loopGap: Math.max(0, Number(step.burstInterval ?? 1.0) || 0),

                            burstsLimit: Math.max(0, Math.round(Number(step.burstsLimit ?? 0) || 0)),

                            clearOnStart: !!step.clearExisting,

                        };

                        window.dispatchEvent(

                            new CustomEvent("EPIC3D_PACKET_CTRL", {

                                detail: {

                                    action: "start",

                                    ...(isAll ? { all: true } : { linkId }),

                                    overrides,

                                },

                            })

                        );

                        // Back-compat: legacy events (harmless if unused)

                        window.dispatchEvent(

                            new CustomEvent("EPIC3D_PACKET_SEND", {

                                detail: { linkId, ...overrides, burstInterval: overrides.loopGap },

                            })

                        );

                    } else if (step.type === "packetStop") {

                        const clear = step.stopLoopsOnly ? false : (step.clearInFlight ?? true) !== false;

                        window.dispatchEvent(

                            new CustomEvent("EPIC3D_PACKET_CTRL", {

                                detail: {

                                    action: "stop",

                                    ...(isAll ? { all: true } : { linkId }),

                                    clear,

                                },

                            })

                        );

                        // Back-compat: legacy events

                        window.dispatchEvent(

                            new CustomEvent("EPIC3D_PACKET_STOP", {

                                detail: {

                                    linkId,

                                    stopLoopsOnly: !!step.stopLoopsOnly,

                                    clearInFlight: (step.clearInFlight ?? true) !== false,

                                },

                            })

                        );

                    }

                } catch (err) {

                    if (process.env.NODE_ENV !== "production") console.warn("Packet action dispatch failed", err);

                }

            };

            if (startSec <= 0) runPkt();

            else setTimeout(runPkt, startSec * 1000);

        };


        const scheduleFadeStep = (step, startSec) => {
            const runFade = () => {
                try {
                    const rawAction = String(step.fadeAction || step.action || step.mode || 'toggle').toLowerCase().trim();
                    const actionKey = rawAction.replace(/[^a-z]/g, '');
                    const action = (actionKey === 'fadein' ? 'in' : (actionKey === 'fadeout' ? 'out' : actionKey)) || 'toggle';
                    const targetKind = String(step.targetKind || 'node').toLowerCase().trim();

                    const detail = {
                        action: action || 'toggle',
                        force: (step.force ?? true) !== false,
                        includeNodesInRooms: (step.includeNodesInRooms ?? true) !== false,
                    };

                    // Only include durations when user actually set a positive value.
                    // (Many numeric inputs serialize as 0 by default; 0 would make fades instant.)
                    const numPos = (v) => {
                        if (v === '' || v == null) return null;
                        const n = Number(v);
                        if (!Number.isFinite(n)) return null;
                        return n > 0 ? n : null;
                    };

                    const dIn = numPos(step.durationIn);
                    const dOut = numPos(step.durationOut);
                    const dAny = numPos(step.duration);
                    if (dIn != null) detail.durationIn = dIn;
                    if (dOut != null) detail.durationOut = dOut;
                    if (dAny != null) detail.duration = dAny;
                    if (detail.action === 'set') detail.alpha = Math.max(0, Math.min(1, Number(step.alpha ?? step.opacity ?? 1) || 0));

                    const isAllToken = (v) => v === '__ALL__' || v === '__ALL_GROUP__' || v === '__ALL_PACKET__' || v === '*' || v === '__ALL_DECK__';

                    const resolveNodeIds = (input) => {
                        if (!input) return [];
                        const needle = String(input).trim();
                        if (!needle) return [];
                        const list = nodes || [];
                        // Exact id match
                        const exactId = list.find((n) => String(n?.id) === needle);
                        if (exactId?.id) return [exactId.id];
                        const lower = needle.toLowerCase();
                        // Exact label/name match (case-insensitive)
                        const exactByLabel = list.filter((n) => {
                            const label = String(n?.label || "").toLowerCase();
                            const name = String(n?.name || "").toLowerCase();
                            return label === lower || name === lower;
                        });
                        if (exactByLabel.length) return exactByLabel.map((n) => n.id).filter(Boolean);
                        // Fallback: contains
                        const partial = list.filter((n) => {
                            const label = String(n?.label || "").toLowerCase();
                            const name = String(n?.name || "").toLowerCase();
                            return (label && label.includes(lower)) || (name && name.includes(lower));
                        });
                        return partial.map((n) => n.id).filter(Boolean);
                    };

                    const applyNodeFadeState = (ids, actionType, alphaValue) => {
                        if (!ids || !ids.length) return;
                        const idSet = new Set(ids.map((v) => String(v)));
                        const clamp01 = (v) => Math.max(0, Math.min(1, Number(v) || 0));
                        setNodes((prev) => (prev || []).map((n) => {
                            if (!n || n.id == null) return n;
                            if (!idSet.has(String(n.id))) return n;
                            const cur = Number.isFinite(Number(n?.fade?.state)) ? Number(n.fade.state) : 1;
                            let next = cur;
                            if (actionType === 'in' || actionType === 'show') next = 1;
                            else if (actionType === 'out' || actionType === 'hide') next = 0;
                            else if (actionType === 'toggle') next = cur > 0.5 ? 0 : 1;
                            else if (actionType === 'set') next = clamp01(alphaValue);
                            if (Math.abs(next - cur) < 0.0001) return n;
                            return {
                                ...n,
                                fade: {
                                    ...(n.fade || {}),
                                    state: next,
                                },
                            };
                        }));
                    };

                    if (targetKind === 'all') {
                        detail.all = true;
                    } else if (targetKind === 'node') {
                        if (isAllToken(step.nodeId)) {
                            detail.nodeIds = (nodes || []).map((n) => n.id);
                        } else if (step.nodeId) {
                            const resolved = resolveNodeIds(step.nodeId);
                            if (resolved.length) detail.nodeIds = resolved;
                            else detail.nodeId = step.nodeId;
                        }
                    } else if (targetKind === 'room') {
                        if (isAllToken(step.roomId)) detail.roomIds = (rooms || []).map((r) => r.id);
                        else if (step.roomId) detail.roomId = step.roomId;
                    } else if (targetKind === 'deck') {
                        if (isAllToken(step.deckId)) detail.deckIds = (decks || []).map((d) => d.id);
                        else if (step.deckId) detail.deckId = step.deckId;
                    } else if (targetKind === 'cluster') {
                        const cid = step.clusterId || step.cluster || '';
                        if (!cid) return;
                        if (isAllToken(cid)) {
                            detail.nodeIds = (nodes || []).map((n) => n.id);
                        } else {
                            detail.nodeIds = (nodes || []).filter((n) => String(n?.cluster || '').toLowerCase() === String(cid).toLowerCase()).map((n) => n.id);
                        }
                        if (!detail.nodeIds || detail.nodeIds.length === 0) return;
                        detail.clusterId = cid;
                    } else if (targetKind === 'group') {
                        const gid = step.groupId;
                        if (!gid) return;
                        const gids = isAllToken(gid) ? (groups || []).map((g) => g.id) : [gid];
                        if (gids.length === 0) return;
                        detail.groupIds = gids;
                        if (!isAllToken(gid)) detail.groupId = gid;

                        // Also expand to explicit roomIds/nodeIds so nodes inside grouped rooms fade too
                        const roomIds = (rooms || []).filter((r) => r.groupId && gids.includes(r.groupId)).map((r) => r.id);
                        const nodeIds = (nodes || []).filter((n) => n.groupId && gids.includes(n.groupId)).map((n) => n.id);
                        if (roomIds.length) detail.roomIds = Array.from(new Set([...(detail.roomIds || []), ...roomIds]));
                        if (nodeIds.length) detail.nodeIds = Array.from(new Set([...(detail.nodeIds || []), ...nodeIds]));
                    }
                    if (targetKind === 'node' && Array.isArray(detail.nodeIds) && detail.nodeIds.length) {
                        applyNodeFadeState(detail.nodeIds, detail.action, detail.alpha);
                    }
                    window.dispatchEvent(new CustomEvent('EPIC3D_FADE_CTRL', { detail }));
                } catch (err) {
                    if (process.env.NODE_ENV !== 'production') console.warn('Fade action dispatch failed', err);
                }
            };

            if (startSec <= 0) runFade();
            else setTimeout(runFade, startSec * 1000);
        };

        const scheduleNodeStep = (step, startSec) => {
            const runNode = () => {
                if (!step.nodeId) {
                    // If no node is targeted, treat Toggle Light as a global scene-lights toggle.
                    if (step.type === "toggleLight") {
                        setShowLights((cur) => !cur);
                    } else if (process.env.NODE_ENV !== "production") {
                        console.warn("Action step has no nodeId:", step);
                    }
                    return;
                }

                const n = nodes.find((x) => x.id === step.nodeId);
                if (!n) return;

                if (step.type === "toggleLight") {
                    toggleLightEnabled(n.id);
                } else if (step.type === "toggleGlow") {
                    setNode(n.id, {glowOn: !n.glowOn});
                } else if (step.type === "setSignalStyle") {
                    setNode(n.id, {
                        signal: {
                            ...(n.signal || {}),
                            style: step.value || "waves",
                        },
                    });
                } else if (step.type === "setTextBox") {            // ?? NEW
                    const tb = n.textBox || {};
                    const targetOn = (step.value || "on") === "on";

                    // bump triggerId when turning on, so animation restarts
                    const nextTrigger = (tb.triggerId || 0) + 1;

                    setNode(n.id, {
                        textBox: {
                            ...tb,
                            enabled: targetOn,
                            triggerId: targetOn ? nextTrigger : (tb.triggerId || 0),
                        },
                    });

                } else if (step.type === "textBoxFade") {
                    const tb = n.textBox || {};
                    const rawMode = step.fadeMode || "in"; // "in" | "out" | "show" | "hide"
                    const duration =
                        step.duration === "" || step.duration == null
                            ? null
                            : Number(step.duration) || 0;

                    let commandType = null;
                    if (rawMode === "in" || rawMode === "fadeIn") commandType = "fadeIn";
                    else if (rawMode === "out" || rawMode === "fadeOut") commandType = "fadeOut";
                    else if (rawMode === "show") commandType = "show";
                    else if (rawMode === "hide") commandType = "hide";

                    if (!commandType) return;

                    setNode(n.id, {
                        textBox: {
                            ...tb,
                            enabled: true,
                            useTimers: false, // manual mode
                            commandType,
                            commandDuration: duration,
                            commandId: (tb.commandId || 0) + 1, // bump so NodeTextBox runs it
                        },
                    });
                } else if (step.type === "textBox") {
                    const n = nodes.find((x) => x.id === step.nodeId);
                    if (!n) return;

                    const tb = n.textBox || {};
                    const mode = step.mode || "toggle"; // "on" | "off" | "fade" | "toggle"

                    if (mode === "fade") {
                        // Trigger the fade sequence (manual fade)
                        setNode(n.id, {
                            textBox: {
                                ...tb,
                                // make sure the textbox exists
                                enabled: true,
                                // bump triggerId so NodeTextBox runs its fade animation
                                triggerId: (tb.triggerId || 0) + 1,
                            },
                        });
                    } else {
                        // Simple visibility control
                        let enabled;
                        if (mode === "on") {
                            enabled = true;
                        } else if (mode === "off") {
                            enabled = false;
                        } else {
                            // toggle
                            enabled = !tb.enabled;
                        }

                        setNode(n.id, {
                            textBox: {
                                ...tb,
                                enabled,
                            },
                        });
                    }
                }
            };

            if (startSec <= 0) runNode();
            else setTimeout(runNode, startSec * 1000);
        };


        const scheduleRoomStep = (step, startSec) => {
            if (!step.roomId) {
                if (process.env.NODE_ENV !== 'production') {
                    console.warn('Action step has no roomId:', step);
                }
                return;
            }

            const runRoom = () => {
                const mode = String(step.mode || step.value || 'toggle').toLowerCase().trim();
                const isAll = step.roomId === '__ALL__' || step.roomId === '*' || step.roomId === '__ALL_ROOM__';
                const targetIds = isAll ? (rooms || []).map((x) => x.id) : [step.roomId];
                if (targetIds.length === 0) return;

                const fadeDurRaw = (step.fadeDuration ?? step.transitionDuration ?? step.durationFade ?? step.fadeSeconds ?? null);
                const fadeDur = (fadeDurRaw === '' || fadeDurRaw == null)
                    ? 0.6
                    : Math.max(0.01, Number(fadeDurRaw) || 0.6);

                const nowRooms = rooms || [];
                const nextHiddenById = new Map();
                for (const rid of targetIds) {
                    const r = nowRooms.find((x) => x.id === rid);
                    if (!r) continue;
                    const nextHidden = (mode === 'hide') ? true : (mode === 'show') ? false : !r.hidden;
                    if (nextHidden !== r.hidden) nextHiddenById.set(rid, nextHidden);
                }

                const toHide = [...nextHiddenById.entries()].filter(([, h]) => h).map(([id]) => id);
                const toShow = [...nextHiddenById.entries()].filter(([, h]) => !h).map(([id]) => id);

                const dispatchFade = (detail) => {
                    try {
                        window.dispatchEvent(new CustomEvent('EPIC3D_FADE_CTRL', { detail }));
                    } catch (err) {
                        if (process.env.NODE_ENV !== 'production') console.warn('Room fade dispatch failed', err);
                    }
                };

                // Hide: fade first, then actually set room.hidden so SceneInner unmounts it.
                if (toHide.length > 0) {
                    // Clear selection immediately (avoid interacting with a fading-out entity)
                    setSelected((sel) => {
                        if (!sel) return sel;
                        if (sel.type === 'room' && toHide.includes(sel.id)) return null;
                        if (sel.type === 'node') {
                            const n = nodes.find((x) => x.id === sel.id);
                            if (n && n.roomId && toHide.includes(n.roomId)) return null;
                        }
                        return sel;
                    });
                    setMultiSel((prev) =>
                        (prev || []).filter((it) => {
                            if (it.type === 'room') return !toHide.includes(it.id);
                            if (it.type === 'node') {
                                const n = nodes.find((x) => x.id === it.id);
                                return !(n && n.roomId && toHide.includes(n.roomId));
                            }
                            return true;
                        })
                    );

                    dispatchFade({
                        action: 'out',
                        force: true,
                        includeNodesInRooms: true,
                        roomIds: toHide,
                        durationOut: fadeDur,
                    });

                    const hideCommitDelayMs = Math.max(16, Math.round(fadeDur * 1000) + 50);
                    setTimeout(() => {
                        setRooms((prev) => prev.map((rm) => (toHide.includes(rm.id) ? { ...rm, hidden: true } : rm)));
                    }, hideCommitDelayMs);
                }

                // Show: snap hidden targets to alpha=0 first, then unhide and fade in.
                if (toShow.length > 0) {
                    dispatchFade({
                        action: 'set',
                        alpha: 0,
                        force: true,
                        includeNodesInRooms: true,
                        roomIds: toShow,
                        duration: 0.0001,
                    });

                    setRooms((prev) => prev.map((rm) => (toShow.includes(rm.id) ? { ...rm, hidden: false } : rm)));

                    setTimeout(() => {
                        dispatchFade({
                            action: 'in',
                            force: true,
                            includeNodesInRooms: true,
                            roomIds: toShow,
                            durationIn: fadeDur,
                            durationOut: fadeDur,
                        });
                    }, 16);
                }
            };

            if (startSec <= 0) runRoom();
            else setTimeout(runRoom, startSec * 1000);
        };

        const scheduleHudBgStep = (step, startSec) => {
            const color = step?.hudBgColor || step?.color || "";
            if (!color) return;
            const duration = Math.max(0, Number(step?.hudBgDuration ?? step?.duration ?? 0.35) || 0.35);

            const runHud = () => {
                try {
                    startBgFade(color, duration);
                } catch (err) {
                    if (process.env.NODE_ENV !== "production") {
                        console.warn("Failed to fade canvas background", err);
                    }
                }
            };

            if (startSec <= 0) runHud();
            else setTimeout(runHud, startSec * 1000);
        };


        const scheduleGroupStep = (step, startSec) => {
            if (!step.groupId) {
                if (process.env.NODE_ENV !== 'production') {
                    console.warn('Action step has no groupId:', step);
                }
                return;
            }

            const runGroup = () => {
                const mode = String(step.mode || step.value || 'toggle').toLowerCase().trim();

                const isAll = step.groupId === '__ALL__' || step.groupId === '*' || step.groupId === '__ALL_GROUP__';
                const targetIds = isAll ? (groups || []).map((g) => g.id) : [step.groupId];
                if (targetIds.length === 0) return;

                const fadeDurRaw = (step.fadeDuration ?? step.transitionDuration ?? step.durationFade ?? step.fadeSeconds ?? null);
                const fadeDur = (fadeDurRaw === '' || fadeDurRaw == null)
                    ? 0.6
                    : Math.max(0.01, Number(fadeDurRaw) || 0.6);

                const nowGroups = groups || [];
                const nextHiddenById = new Map();
                for (const gid of targetIds) {
                    const g = nowGroups.find((x) => x.id === gid);
                    if (!g) continue;
                    const nextHidden = (mode === 'hide') ? true : (mode === 'show') ? false : !g.hidden;
                    if (nextHidden !== g.hidden) nextHiddenById.set(gid, nextHidden);
                }

                const toHide = [...nextHiddenById.entries()].filter(([, h]) => h).map(([id]) => id);
                const toShow = [...nextHiddenById.entries()].filter(([, h]) => !h).map(([id]) => id);

                const dispatchFade = (detail) => {
                    try {
                        window.dispatchEvent(new CustomEvent('EPIC3D_FADE_CTRL', { detail }));
                    } catch (err) {
                        if (process.env.NODE_ENV !== 'production') console.warn('Group fade dispatch failed', err);
                    }
                };

                const roomIdsForGroups = (gids) => (rooms || []).filter((r) => r.groupId && gids.includes(r.groupId)).map((r) => r.id);
                const nodeIdsForGroups = (gids) => (nodes || []).filter((n) => n.groupId && gids.includes(n.groupId)).map((n) => n.id);

                // Hide: fade first while group is still rendered, then set g.hidden so renderNodes/renderRooms drop it.
                if (toHide.length > 0) {
                    const roomIds = roomIdsForGroups(toHide);
                    const nodeIds = nodeIdsForGroups(toHide);

                    // Clear selection immediately
                    setSelected((sel) => {
                        if (!sel) return sel;
                        if (sel.type === 'room') {
                            const r = rooms.find((x) => x.id === sel.id);
                            if (r && r.groupId && toHide.includes(r.groupId)) return null;
                        }
                        if (sel.type === 'node') {
                            const n = nodes.find((x) => x.id === sel.id);
                            if (n && n.groupId && toHide.includes(n.groupId)) return null;
                            // Also clear nodes living in rooms that are in the group
                            if (n && n.roomId && roomIds.includes(n.roomId)) return null;
                        }
                        return sel;
                    });
                    setMultiSel((prev) =>
                        (prev || []).filter((it) => {
                            if (it.type === 'room') {
                                const r = rooms.find((x) => x.id === it.id);
                                return !(r && r.groupId && toHide.includes(r.groupId));
                            }
                            if (it.type === 'node') {
                                const n = nodes.find((x) => x.id === it.id);
                                if (n && n.groupId && toHide.includes(n.groupId)) return false;
                                if (n && n.roomId && roomIds.includes(n.roomId)) return false;
                            }
                            return true;
                        })
                    );

                    dispatchFade({
                        action: 'out',
                        force: true,
                        includeNodesInRooms: true,
                        groupIds: toHide,
                        roomIds,
                        nodeIds,
                        durationOut: fadeDur,
                    });

                    const hideCommitDelayMs = Math.max(16, Math.round(fadeDur * 1000) + 50);
                    setTimeout(() => {
                        setGroups((prev) => prev.map((g) => (toHide.includes(g.id) ? { ...g, hidden: true } : g)));
                    }, hideCommitDelayMs);
                }

                // Show: snap hidden targets to alpha=0 first, then unhide and fade in.
                if (toShow.length > 0) {
                    const roomIds = roomIdsForGroups(toShow);
                    const nodeIds = nodeIdsForGroups(toShow);

                    dispatchFade({
                        action: 'set',
                        alpha: 0,
                        force: true,
                        includeNodesInRooms: true,
                        groupIds: toShow,
                        roomIds,
                        nodeIds,
                        duration: 0.0001,
                    });

                    setGroups((prev) => prev.map((g) => (toShow.includes(g.id) ? { ...g, hidden: false } : g)));

                    setTimeout(() => {
                        dispatchFade({
                            action: 'in',
                            force: true,
                            includeNodesInRooms: true,
                            groupIds: toShow,
                            roomIds,
                            nodeIds,
                            durationIn: fadeDur,
                            durationOut: fadeDur,
                        });
                    }, 16);
                }
            };

            if (startSec <= 0) runGroup();
            else setTimeout(runGroup, startSec * 1000);
        };

        const schedulePictureStep = (step, startSec) => {
            const targetRaw = String(step.pictureTarget || step.target || "all").toLowerCase();
            const targetKey = targetRaw.replace(/[^a-z]/g, "");
            const modeRaw = String(step.pictureMode || step.mode || "enable").toLowerCase();
            const modeKey = modeRaw.replace(/[^a-z]/g, "");
            const duration = Math.max(0.01, Number(step.fadeDuration ?? step.duration ?? 0.6) || 0.6);

            const runPics = () => {
                const pics = importedPicturesRef.current || [];
                const findByName = (name) => {
                    const nn = String(name || '').trim().toLowerCase();
                    if (!nn) return null;
                    return pics.find((p) => String(p?.name || '').trim().toLowerCase() === nn) ||
                        pics.find((p) => String(p?.name || '').trim().toLowerCase().includes(nn)) ||
                        null;
                };
                let ids = [];
                const isSingle = (targetKey === "picture" || targetKey === "single" || targetKey === "singlepicture");
                if (isSingle) {
                    const requestedId = step.pictureId || '';
                    if (requestedId) {
                        const hit = pics.find((p) => p?.id === requestedId);
                        if (hit?.id) ids = [hit.id];
                    }
                    if (!ids.length) {
                        const byName = findByName(step.pictureName || requestedId);
                        if (byName?.id) ids = [byName.id];
                    }
                } else if (targetKey === "local") {
                    ids = pics.filter((p) => !!p?.localKey).map((p) => p.id);
                } else if (targetKey === "custom") {
                    ids = pics.filter((p) => !p?.localKey).map((p) => p.id);
                } else {
                    ids = pics.map((p) => p.id);
                }
                ids = ids.filter(Boolean);
                if (!ids.length) return;

                if (modeKey === "enable" || modeKey === "show") {
                    setImportedPictures((prev) =>
                        (Array.isArray(prev) ? prev : []).map((p) =>
                            ids.includes(p.id) ? { ...p, visible: true, opacity: (Number.isFinite(Number(p.opacity)) && Number(p.opacity) > 0) ? p.opacity : 1 } : p
                        ),
                    );
                    return;
                }
                if (modeKey === "disable" || modeKey === "hide") {
                    setImportedPictures((prev) =>
                        (Array.isArray(prev) ? prev : []).map((p) =>
                            ids.includes(p.id) ? { ...p, visible: false } : p
                        ),
                    );
                    return;
                }
                if (modeKey === "fadein") {
                    const fromOverrides = {};
                    setImportedPictures((prev) =>
                        (Array.isArray(prev) ? prev : []).map((p) =>
                            ids.includes(p.id) ? (fromOverrides[p.id] = 0, { ...p, visible: true, opacity: 0 }) : p
                        ),
                    );
                    animatePictureOpacity(ids, 1, duration, false, fromOverrides);
                    return;
                }
                if (modeKey === "fadeout") {
                    const fromOverrides = {};
                    setImportedPictures((prev) =>
                        (Array.isArray(prev) ? prev : []).map((p) =>
                            ids.includes(p.id)
                                ? (() => {
                                    const base = Number.isFinite(Number(p.opacity)) ? Number(p.opacity) : 1;
                                    const start = base <= 0.01 ? 1 : base;
                                    fromOverrides[p.id] = start;
                                    return { ...p, visible: true, opacity: start };
                                })()
                                : p
                        ),
                    );
                    animatePictureOpacity(ids, 0, duration, true, fromOverrides);
                    return;
                }
            };

            if (startSec <= 0) runPics();
            else setTimeout(runPics, startSec * 1000);
        };

        const scheduleLinkActiveStep = (step, startSec) => {
            const targetOn = (step.value || "on") === "on";
            const linkId = step.linkId || "";
            const nodeId = step.nodeId || "";
            if (!linkId && !nodeId) return;

            const runLink = () => {
                setLinks((prev) =>
                    prev.map((l) => {
                        if (!l) return l;
                        if (linkId) {
                            if (l.id !== linkId) return l;
                            if ((l.active ?? true) === targetOn) return l;
                            return { ...l, active: targetOn };
                        }
                        if (nodeId && l.from === nodeId) {
                            if ((l.active ?? true) === targetOn) return l;
                            return { ...l, active: targetOn };
                        }
                        return l;
                    }),
                );
            };

            if (startSec <= 0) runLink();
            else setTimeout(runLink, startSec * 1000);
        };

        const runLinkSetSwitchForNode = (nodeId, targetSetId, fadeCfg) => {
            if (!nodeId || !targetSetId) return;
            const node = (nodesRef.current || []).find((n) => n?.id === nodeId);
            if (!node) return;
            const sets = getNodeLinkSets(node);
            const currentSetId = node?.activeLinkSetId || sets[0]?.id || LINK_SET_DEFAULT_ID;
            if (!currentSetId || currentSetId === targetSetId) return;

            const linksNow = linksRef.current || [];
            const resolveSetId = (l, fallbackId) => l?.linkSetId || fallbackId || LINK_SET_DEFAULT_ID;
            const oldIds = linksNow
                .filter((l) => l?.from === nodeId && resolveSetId(l, currentSetId) === currentSetId)
                .map((l) => l.id)
                .filter(Boolean);
            const newIds = linksNow
                .filter((l) => l?.from === nodeId && resolveSetId(l, targetSetId) === targetSetId)
                .map((l) => l.id)
                .filter(Boolean);

            const fadeOn = !!fadeCfg?.fade;
            const fadeOut = Math.max(0, Number(fadeCfg?.fadeOutDuration ?? 0) || 0);
            const fadeIn = Math.max(0, Number(fadeCfg?.fadeInDuration ?? 0) || 0);

            const doSwitch = () => {
                setNodeById(nodeId, {
                    linkSets: sets,
                    activeLinkSetId: targetSetId,
                });

                if (newIds.length) {
                    setLinkFadeOverrides(newIds, 0);
                    animateLinkFadeOverrides(newIds, 1, fadeIn, true);
                }
                if (oldIds.length) {
                    setLinkFadeOverrides(oldIds, null);
                }
            };

            if (!fadeOn) {
                doSwitch();
                return;
            }

            if (oldIds.length) {
                animateLinkFadeOverrides(oldIds, 0, fadeOut, false);
            }

            if (fadeOut > 0.0001) {
                setTimeout(doSwitch, fadeOut * 1000);
            } else {
                doSwitch();
            }
        };

        const scheduleLinkSetSwitchStep = (step, startSec) => {
            const nodeId = step.nodeId || "";
            const targetSetId = step.linkSetId || "";
            if (!nodeId || !targetSetId) return;
            const fadeCfg = {
                fade: step.fade ?? true,
                fadeOutDuration: step.fadeOutDuration ?? 0.35,
                fadeInDuration: step.fadeInDuration ?? 0.35,
            };
            const runSwitch = () => runLinkSetSwitchForNode(nodeId, targetSetId, fadeCfg);
            if (startSec <= 0) runSwitch();
            else setTimeout(runSwitch, startSec * 1000);
        };

        const scheduleLinkSetSwitchAllStep = (step, startSec) => {
            const targetLabel = __normalizeLinkSetLabel(step.setLabel || "");
            if (!targetLabel) return;
            const fadeCfg = {
                fade: step.fade ?? true,
                fadeOutDuration: step.fadeOutDuration ?? 0.35,
                fadeInDuration: step.fadeInDuration ?? 0.35,
            };
            const runSwitchAll = () => {
                const nodesNow = nodesRef.current || [];
                nodesNow.forEach((node) => {
                    const sets = getNodeLinkSets(node);
                    const target = sets.find((set, idx) => __normalizeLinkSetLabel(__linkSetLabel(set, idx)) === targetLabel);
                    if (!target?.id) return;
                    runLinkSetSwitchForNode(node.id, target.id, fadeCfg);
                });
            };
            if (startSec <= 0) runSwitchAll();
            else setTimeout(runSwitchAll, startSec * 1000);
        };

        const scheduleLinkSetStatusAllStep = (step, startSec) => {
            const targetLabel = __normalizeLinkSetLabel(step.setLabel || "");
            if (!targetLabel) return;
            const targetOn = (step.value || "on") === "on";
            const runStatus = () => {
                const nodesNow = nodesRef.current || [];
                const nodeById = new Map(nodesNow.map((n) => [n?.id, n]));
                setLinks((prev) =>
                    prev.map((l) => {
                        if (!l) return l;
                        const node = nodeById.get(l.from);
                        if (!node) return l;
                        const sets = getNodeLinkSets(node);
                        const activeSetId = node?.activeLinkSetId || sets[0]?.id || LINK_SET_DEFAULT_ID;
                        const resolvedSetId = l.linkSetId || activeSetId;
                        const idx = sets.findIndex((s) => s.id === resolvedSetId);
                        const label = idx >= 0 ? __linkSetLabel(sets[idx], idx) : LINK_SET_DEFAULT_NAME;
                        if (__normalizeLinkSetLabel(label) !== targetLabel) return l;
                        if ((l.active ?? true) === targetOn) return l;
                        return { ...l, active: targetOn };
                    }),
                );
            };
            if (startSec <= 0) runStatus();
            else setTimeout(runStatus, startSec * 1000);
        };

        const scheduleEventStep = (step, startSec) => {
            const eventId = step.eventId || "";
            if (!eventId) return;
            const mode = String(step.eventMode || "enable").toLowerCase();
            const runEvent = () => {
                setEvents((prev) => prev.map((ev) => {
                    if (!ev || ev.id !== eventId) return ev;
                    if (mode === "toggle") return { ...ev, enabled: !(ev.enabled !== false) };
                    if (mode === "disable" || mode === "off") return { ...ev, enabled: false };
                    return { ...ev, enabled: true };
                }));
            };
            if (startSec <= 0) runEvent();
            else setTimeout(runEvent, startSec * 1000);
        };

        const steps = action.steps || [];
        const camStepIndices = [];
        steps.forEach((step, idx) => {
            if (step?.type === "cameraMove") camStepIndices.push(idx);
        });
        const camStepPosByIndex = new Map();
        camStepIndices.forEach((idx, pos) => camStepPosByIndex.set(idx, pos));

        steps.forEach((s, stepIdx) => {
            if (!s) return;

            const delay = Math.max(0, Number(s.delay || 0));
            let parentStart = 0;
            // --- HUD fade step (buttons) ---
            if (s.type === "hudFade") {
                const targetId = s.hudTargetId || "";
                if (targetId) {
                    const mode = (s.hudMode || "out") === "in" ? "in" : "out";
                    const duration = Math.max(0.01, Number(s.hudDuration || 0.35));
                    try {
                        window.dispatchEvent(
                            new CustomEvent("EPIC3D_HUD_FADE", {
                                detail: { targetIds: [targetId], mode, duration },
                            })
                        );
                    } catch (err) {
                        if (process.env.NODE_ENV !== "production") {
                            console.warn("Failed to dispatch HUD fade event", err);
                        }
                    }
                }
                return;
            }
            if (s.type === "hudBgFade") {
                parentStart = delay;
                scheduleHudBgStep(s, parentStart);
            }

            // ---------- Camera track step (top-level, chained) ----------
            else if (s.type === "cameraMove") {
                const duration = Math.max(0.001, Number(s.duration || 0));
                const fromPresetId = s.fromPresetId || null;
                const toPresetId = s.toPresetId || null;
                if (!toPresetId) return; // need a destination view

                parentStart = cameraCursor + delay;
                const camPos = camStepPosByIndex.get(stepIdx);
                const prevCamIdx = camPos !== undefined ? camStepIndices[camPos - 1] : undefined;
                const nextCamIdx = camPos !== undefined ? camStepIndices[camPos + 1] : undefined;
                const prevContinuous = prevCamIdx !== undefined ? !!steps[prevCamIdx]?.continuous : false;
                const continuousIn = prevContinuous;
                const continuousOut = !!s.continuous && nextCamIdx !== undefined;

                // Schedule on the camera queue; SceneInner will read + animate
                scheduleCameraMove({
                    fromPresetId,
                    toPresetId,
                    startDelay: parentStart,
                    duration,
                    continuous: !!s.continuous,
                    continuousIn,
                    continuousOut,
                });

                // Next camera move starts after this one
                cameraCursor = parentStart + duration;
            }
            // ---------- Camera turntable orbit ----------
            else if (s.type === "cameraTurntable") {
                const centerNodeId = s.centerNodeId || s.nodeId || null;
                if (!centerNodeId) return;
                parentStart = delay;

                const orbitDistanceRaw = Number(s.orbitDistance ?? 0);
                const orbitSpeed = Number(s.orbitSpeed ?? 0);
                const orbitDirection = (s.orbitDirection || 'left') === 'right' ? 'right' : 'left';
                const orbitVertical = !!s.orbitVertical;
                const orbitVerticalRange = Math.max(0, Number(s.orbitVerticalRange ?? 1) || 1);

                const moveToStart = !!s.moveToStart;
                const moveDuration = Math.max(0.01, Number(s.moveDuration ?? 1.5) || 1.5);
                const fromPresetId = s.fromPresetId || null;
                const toPresetId = s.toPresetId || null;

                let startDelay = parentStart;
                let startPresetId = null;
                if (moveToStart) {
                    if (!toPresetId) return;
                    scheduleCameraMove({
                        fromPresetId,
                        toPresetId,
                        startDelay: parentStart,
                        duration: moveDuration,
                        continuous: false,
                        continuousIn: false,
                        continuousOut: false,
                    });
                    startDelay = parentStart + moveDuration;
                    startPresetId = toPresetId;
                }

                scheduleCameraTurntable({
                    centerNodeId,
                    orbitDistance: orbitDistanceRaw,
                    orbitSpeed,
                    orbitDirection,
                    orbitVertical,
                    orbitVerticalRange,
                    startDelay,
                    startPresetId,
                    requireMatch: true,
                });
            }
            // ---------- Global wireframe step (absolute timing) ----------
            else if (s.type === "setWireframe") {
                parentStart = delay;
                scheduleWireStep(s, parentStart);
            }
            // ---------- Wireframe opacity steps (absolute timing) ----------
            else if (s.type === "setWireOpacity") {
                parentStart = delay;
                scheduleWireOpacityStep(s, parentStart);
            }
            // ---------- Packet steps (absolute timing) ----------
            else if (s.type === "packetSend" || s.type === "packetStop") {
                parentStart = delay;
                schedulePacketStep(s, parentStart);
            }
            // ---------- Scene fade steps (absolute timing) ----------
            else if (s.type === 'fade') {
                parentStart = delay;
                scheduleFadeStep(s, parentStart);
            }
            // ---------- Event steps (absolute timing) ----------
            else if (s.type === 'event') {
                parentStart = delay;
                scheduleEventStep(s, parentStart);
            }
            // ---------- Room visibility steps (absolute timing) ----------
            else if (s.type === 'setRoomVisible') {
                parentStart = delay;
                scheduleRoomStep(s, parentStart);
            }
            // ---------- Group visibility steps (absolute timing) ----------
            else if (s.type === 'setGroupVisible') {
                parentStart = delay;
                scheduleGroupStep(s, parentStart);
            }
            // ---------- Picture steps (absolute timing) ----------
            else if (s.type === 'setPictures') {
                parentStart = delay;
                schedulePictureStep(s, parentStart);
            }
            // ---------- Link active/inactive steps (absolute timing) ----------
            else if (s.type === 'setLinkActive') {
                parentStart = delay;
                scheduleLinkActiveStep(s, parentStart);
            }
            else if (s.type === 'switchLinkSet') {
                parentStart = delay;
                scheduleLinkSetSwitchStep(s, parentStart);
            }
            else if (s.type === 'switchLinkSetAll') {
                parentStart = delay;
                scheduleLinkSetSwitchAllStep(s, parentStart);
            }
            else if (s.type === 'setLinkSetStatus') {
                parentStart = delay;
                scheduleLinkSetStatusAllStep(s, parentStart);
            }
            else if (s.type === 'setSceneLights') {
                parentStart = delay;
                scheduleSceneLightsStep(s, parentStart);
            }
            // ---------- Node-targeted steps (absolute timing) ----------
            else {
                parentStart = delay;
                scheduleNodeStep(s, parentStart);
            }
            // ---------- Child steps: run relative to parentStart ----------
            if (Array.isArray(s.children) && s.children.length > 0) {
                s.children.forEach((c) => {
                    if (!c) return;
                    const childDelay = Math.max(0, Number(c.delay || 0));
                    const childStart = parentStart + childDelay;

                    if (c.type === "cameraMove") {
                        // For now, ignore camera moves as children (UI disallows this).
                        return;
                    } else if (c.type === "setWireframe") {
                        scheduleWireStep(c, childStart);
                    } else if (c.type === "setWireOpacity") {
                        scheduleWireOpacityStep(c, childStart);
                    } else if (c.type === "setSceneLights") {
                        scheduleSceneLightsStep(c, childStart);
                    } else if (c.type === "packetSend" || c.type === "packetStop") {
                        schedulePacketStep(c, childStart);
                    } else if (c.type === "hudBgFade") {
                        scheduleHudBgStep(c, childStart);
                    } else if (c.type === 'fade') {
                        scheduleFadeStep(c, childStart);
                    } else if (c.type === 'setRoomVisible') {
                        scheduleRoomStep(c, childStart);
                    } else if (c.type === 'setGroupVisible') {
                        scheduleGroupStep(c, childStart);
                    } else if (c.type === 'setPictures') {
                        schedulePictureStep(c, childStart);
                    } else if (c.type === 'setLinkActive') {
                        scheduleLinkActiveStep(c, childStart);
                    } else if (c.type === 'switchLinkSet') {
                        scheduleLinkSetSwitchStep(c, childStart);
                    } else if (c.type === 'switchLinkSetAll') {
                        scheduleLinkSetSwitchAllStep(c, childStart);
                    } else if (c.type === 'setLinkSetStatus') {
                        scheduleLinkSetStatusAllStep(c, childStart);
                    } else {
                        scheduleNodeStep(c, childStart);
                    }
                });
            }
        });
    }






    // Actions panel: stable component wrapper to prevent unmount/remount while editing
