    const copyRoomNodesToRoom = useCallback(
        (masterRoomId, targetRoomId) => {
            if (!masterRoomId || !targetRoomId) return;
            if (masterRoomId === targetRoomId) return;
            const srcRoom = rooms.find((r) => r.id === masterRoomId);
            const dstRoom = rooms.find((r) => r.id === targetRoomId);
            if (!srcRoom || !dstRoom) return;
            const srcCenter = Array.isArray(srcRoom.center) ? srcRoom.center : [0, 0, 0];
            const dstCenter = Array.isArray(dstRoom.center) ? dstRoom.center : [0, 0, 0];
            const dx = (dstCenter[0] ?? 0) - (srcCenter[0] ?? 0);
            const dy = (dstCenter[1] ?? 0) - (srcCenter[1] ?? 0);
            const dz = (dstCenter[2] ?? 0) - (srcCenter[2] ?? 0);
            const baseLabel = dstRoom.name || dstRoom.id;
            const sourceNodes = nodes.filter((n) => n.roomId === masterRoomId);
            if (!sourceNodes.length) return;
            const nodeIdMap = new Map();
            const additions = sourceNodes.map((n) => {
                const p = Array.isArray(n.position) ? n.position : [0, 0, 0];
                const copy = JSON.parse(JSON.stringify(n || {}));
                const newId = uuid();
                nodeIdMap.set(n.id, newId);
                copy.id = newId;
                copy.label = n.label ? `${n.label} (${baseLabel})` : n.label;
                copy.position = [Number(p[0] ?? 0) + dx, Number(p[1] ?? 0) + dy, Number(p[2] ?? 0) + dz];
                copy.roomId = targetRoomId;
                copy.deckId = dstRoom.deckId || n.deckId;
                return copy;
            });

            const sourceNodeIds = new Set(sourceNodes.map((n) => n.id));
            const linkAdditions = (links || [])
                .filter((l) => sourceNodeIds.has(l.from) && sourceNodeIds.has(l.to))
                .map((l) => {
                    const copy = JSON.parse(JSON.stringify(l || {}));
                    copy.id = uuid();
                    copy.from = nodeIdMap.get(l.from);
                    copy.to = nodeIdMap.get(l.to);
                    if (Array.isArray(copy.breakpoints)) {
                        copy.breakpoints = copy.breakpoints.map((bp) => [
                            (Number(bp?.[0] ?? 0) || 0) + dx,
                            (Number(bp?.[1] ?? 0) || 0) + dy,
                            (Number(bp?.[2] ?? 0) || 0) + dz,
                        ]);
                    }
                    return copy;
                });

            setNodes((prev) => [...prev, ...additions]);
            if (linkAdditions.length) setLinks((prev) => [...prev, ...linkAdditions]);
        },
        [nodes, rooms, links, setNodes, setLinks],
    );

    const runRenameOrganizer = useCallback(() => {
        const typeLabels = {
            tv: "TV",
            ipad: "iPad",
            laviebox: "LAVIE Box",
            accesspoint: "Access Point",
            amplifier: "Amplifier",
            speaker: "Speaker Ceiling",
            speakerfloor: "Speaker Ground",
            soundbar: "Soundbar",
            headphones: "Headphones",
            subwoofer: "Subwoofer",
            remote: "Remote",
            switch: "Switch",
            node: "Node",
        };
        const toTitle = (raw) => {
            const cleaned = String(raw || "")
                .replace(/[_-]+/g, " ")
                .replace(/([a-z])([A-Z])/g, "$1 $2")
                .trim();
            if (!cleaned) return "Node";
            return cleaned
                .split(/\s+/)
                .map((w) => (w ? w[0].toUpperCase() + w.slice(1).toLowerCase() : ""))
                .join(" ");
        };
        const typeLabelFor = (node) => {
            const raw = node?.shape?.type || node?.kind || node?.type || "node";
            const key = String(raw || "").trim().toLowerCase();
            return typeLabels[key] || toTitle(raw);
        };

        const roomNameById = new Map(
            (rooms || [])
                .map((r) => [r.id, String(r?.name || r?.label || r?.id || "").trim()])
                .filter(([, name]) => name.length > 0),
        );

        setNodes((prev) => {
            const counters = new Map();
            return (prev || []).map((n) => {
                if (!n) return n;
                const typeLabel = typeLabelFor(n);
                const roomName = n.roomId
                    ? (roomNameById.get(n.roomId) || String(n.roomId || "").trim())
                    : "";
                const key = `${roomName}::${typeLabel}`;
                const nextIndex = (counters.get(key) || 0) + 1;
                counters.set(key, nextIndex);
                const base = roomName ? `${roomName} ${typeLabel}` : typeLabel;
                return { ...n, label: `${base} ${nextIndex}`.trim() };
            });
        });
    }, [rooms, setNodes]);

